(() => {
  const postPreview = document.getElementById('post-preview');
  const previewViewport = document.getElementById('preview-viewport');
  const previewHolder = document.getElementById('preview-holder');
  const bgImage = document.getElementById('bg-image');
  const logoImage = document.getElementById('logo-image');
  const formatSelect = document.getElementById('format-select');
  const formatNote = document.getElementById('format-note');
  const bgColorInput = document.getElementById('bg-color-input');
  const bgColorText = document.getElementById('bg-color-text');

  const titleInput = document.getElementById('title-input');
  const subtitleInput = document.getElementById('subtitle-input');
  const footerInput = document.getElementById('footer-input');
  const backgroundUpload = document.getElementById('background-upload');
  const logoUpload = document.getElementById('logo-upload');

  const previewTitle = document.getElementById('preview-title');
  const previewSubtitle = document.getElementById('preview-subtitle');
  const previewFooter = document.getElementById('preview-footer');

  const zoomRange = document.getElementById('zoom-range');
  const zoomInBtn = document.getElementById('zoom-in');
  const zoomOutBtn = document.getElementById('zoom-out');
  const resetPositionBtn = document.getElementById('reset-position');
  const exportBtn = document.getElementById('export-btn');
  const statusText = document.getElementById('status-text');
  const darkModeToggle = document.getElementById('dark-mode-toggle');
  const templateButtons = [...document.querySelectorAll('.template-btn')];
  const themeButtons = [...document.querySelectorAll('.theme-btn')];

  const DEFAULT_LOGO_DATA_URL = 'data:image/png;base64,';
  const ZOOM_MIN = Number(zoomRange.min);
  const ZOOM_MAX = Number(zoomRange.max);
  const ZOOM_STEP = Number(zoomRange.step);
  const FORMATS = {
    portrait: { width: 1080, height: 1350, label: 'Portrait 1080 x 1350' },
    square: { width: 1080, height: 1080, label: 'Square 1080 x 1080' },
    landscape: { width: 1080, height: 566, label: 'Landscape 1080 x 566' },
  };

  const state = {
    format: 'portrait',
    width: FORMATS.portrait.width,
    height: FORMATS.portrait.height,
    imageBaseWidth: FORMATS.portrait.width * 1.25,
    imageBaseHeight: FORMATS.portrait.height * 1.25,
    x: 0,
    y: 0,
    scale: 1,
    dragging: false,
    startClientX: 0,
    startClientY: 0,
    startX: 0,
    startY: 0,
    pinchDistance: null,
    pinchStartScale: 1,
    displayScale: 1,
  };

  const clamp = (value, min, max) => Math.min(max, Math.max(min, value));

  const getDistance = (touchA, touchB) => {
    const dx = touchB.clientX - touchA.clientX;
    const dy = touchB.clientY - touchA.clientY;
    return Math.hypot(dx, dy);
  };

  const setStatus = (message) => {
    statusText.textContent = message;
  };

  const applyBaseBackgroundColor = (colorValue) => {
    postPreview.style.setProperty('--post-base-bg', colorValue);
    bgColorInput.value = colorValue;
    bgColorText.value = colorValue.toUpperCase();
  };

  const normalizeHexColor = (value) => {
    const trimmed = value.trim();
    return /^#([0-9a-fA-F]{6})$/.test(trimmed) ? trimmed.toLowerCase() : null;
  };

  const clampImagePosition = () => {
    const scaledWidth = state.imageBaseWidth * state.scale;
    const scaledHeight = state.imageBaseHeight * state.scale;
    const maxOffsetX = Math.max(0, (scaledWidth - state.width) / 2);
    const maxOffsetY = Math.max(0, (scaledHeight - state.height) / 2);

    state.x = clamp(state.x, -maxOffsetX, maxOffsetX);
    state.y = clamp(state.y, -maxOffsetY, maxOffsetY);
  };

  const updateBackgroundLayout = () => {
    const naturalWidth = bgImage.naturalWidth || state.width;
    const naturalHeight = bgImage.naturalHeight || state.height;
    const coverScale = Math.max(state.width / naturalWidth, state.height / naturalHeight);

    state.imageBaseWidth = naturalWidth * coverScale;
    state.imageBaseHeight = naturalHeight * coverScale;

    bgImage.style.width = `${state.imageBaseWidth}px`;
    bgImage.style.height = `${state.imageBaseHeight}px`;

    clampImagePosition();
    applyBackgroundTransform();
  };

  const setTemplate = (templateName) => {
    postPreview.classList.remove('template-minimal', 'template-classic', 'template-bold');
    postPreview.classList.add(`template-${templateName}`);

    templateButtons.forEach((button) => {
      button.classList.toggle('active', button.dataset.template === templateName);
    });
  };

  const setTheme = (themeName) => {
    const nextTheme = themeName === 'moonless' ? 'moonless' : 'light';
    postPreview.classList.remove('theme-light', 'theme-moonless');
    postPreview.classList.add(`theme-${nextTheme}`);

    themeButtons.forEach((button) => {
      button.classList.toggle('active', button.dataset.theme === nextTheme);
    });
  };

  const setFormat = (formatName) => {
    const nextFormat = FORMATS[formatName] || FORMATS.portrait;
    state.format = formatName in FORMATS ? formatName : 'portrait';
    state.width = nextFormat.width;
    state.height = nextFormat.height;

    document.documentElement.style.setProperty('--post-width', String(state.width));
    document.documentElement.style.setProperty('--post-height', String(state.height));

    postPreview.classList.remove('format-portrait', 'format-square', 'format-landscape');
    postPreview.classList.add(`format-${state.format}`);
    formatSelect.value = state.format;
    formatNote.textContent = `Format aktif: ${nextFormat.label}`;

    updateBackgroundLayout();
    updatePreviewScale();
  };

  const applyBackgroundTransform = () => {
    clampImagePosition();
    bgImage.style.transform = `translate(-50%, -50%) translate(${state.x}px, ${state.y}px) scale(${state.scale})`;
  };

  const updatePreviewScale = () => {
    const containerWidth = previewViewport.clientWidth;
    const maxHeight = Math.max(window.innerHeight * 0.62, 280);
    const scaleFromWidth = containerWidth / state.width;
    const scaleFromHeight = maxHeight / state.height;
    const displayScale = clamp(Math.min(scaleFromWidth, scaleFromHeight), 0.2, 1);
    state.displayScale = displayScale;
    previewHolder.style.transform = `scale(${displayScale})`;
    previewViewport.style.height = `${state.height * displayScale}px`;
  };

  const updateTexts = () => {
    previewTitle.textContent = titleInput.value.trim() || 'Judul Konten';
    previewSubtitle.textContent = subtitleInput.value.trim() || 'Subjudul konten';
    previewFooter.textContent = footerInput.value.trim() || 'Footer';
  };

  const readImageAsDataUrl = (file, onDone) => {
    if (!file) return;
    const reader = new FileReader();
    reader.onload = (event) => {
      onDone(event.target?.result || '');
    };
    reader.readAsDataURL(file);
  };

  const setZoom = (nextScale) => {
    state.scale = clamp(Number(nextScale), ZOOM_MIN, ZOOM_MAX);
    zoomRange.value = state.scale.toFixed(2);
    applyBackgroundTransform();
  };

  const resetPosition = () => {
    state.x = 0;
    state.y = 0;
    setZoom(1);
  };

  const startDrag = (clientX, clientY) => {
    state.dragging = true;
    state.startClientX = clientX;
    state.startClientY = clientY;
    state.startX = state.x;
    state.startY = state.y;
  };

  const dragTo = (clientX, clientY) => {
    if (!state.dragging) return;
    const scaleFactor = state.displayScale || 1;
    const deltaX = (clientX - state.startClientX) / scaleFactor;
    const deltaY = (clientY - state.startClientY) / scaleFactor;
    state.x = state.startX + deltaX;
    state.y = state.startY + deltaY;
    applyBackgroundTransform();
  };

  const stopDrag = () => {
    state.dragging = false;
  };

  previewViewport.addEventListener('mousedown', (event) => {
    if (event.button !== 0) return;
    event.preventDefault();
    startDrag(event.clientX, event.clientY);
  });

  window.addEventListener('mousemove', (event) => {
    dragTo(event.clientX, event.clientY);
  });

  window.addEventListener('mouseup', stopDrag);

  previewViewport.addEventListener(
    'touchstart',
    (event) => {
      if (event.touches.length === 2) {
        stopDrag();
        state.pinchDistance = getDistance(event.touches[0], event.touches[1]);
        state.pinchStartScale = state.scale;
      } else if (event.touches.length === 1) {
        const touch = event.touches[0];
        startDrag(touch.clientX, touch.clientY);
      }
    },
    { passive: false }
  );

  previewViewport.addEventListener(
    'touchmove',
    (event) => {
      if (event.touches.length === 2 && state.pinchDistance) {
        event.preventDefault();
        const currentDistance = getDistance(event.touches[0], event.touches[1]);
        const ratio = currentDistance / state.pinchDistance;
        setZoom(state.pinchStartScale * ratio);
      } else if (event.touches.length === 1 && state.dragging) {
        event.preventDefault();
        const touch = event.touches[0];
        dragTo(touch.clientX, touch.clientY);
      }
    },
    { passive: false }
  );

  previewViewport.addEventListener('touchend', (event) => {
    if (event.touches.length < 2) {
      state.pinchDistance = null;
    }
    if (event.touches.length === 0) {
      stopDrag();
    }
  });

  backgroundUpload.addEventListener('change', (event) => {
    const file = event.target.files?.[0];
    readImageAsDataUrl(file, (imageUrl) => {
      bgImage.src = imageUrl;
      setStatus('Gambar utama diperbarui.');
    });
  });

  logoUpload.addEventListener('change', (event) => {
    const file = event.target.files?.[0];
    readImageAsDataUrl(file, (imageUrl) => {
      logoImage.src = imageUrl;
      logoImage.alt = 'Logo kustom';
      setStatus('Logo diperbarui.');
    });
  });

  titleInput.addEventListener('input', updateTexts);
  subtitleInput.addEventListener('input', updateTexts);
  footerInput.addEventListener('input', updateTexts);
  bgImage.addEventListener('load', updateBackgroundLayout);
  bgColorInput.addEventListener('input', () => {
    applyBaseBackgroundColor(bgColorInput.value);
    setStatus(`Warna latar diubah ke ${bgColorInput.value.toUpperCase()}.`);
  });
  bgColorText.addEventListener('change', () => {
    const normalized = normalizeHexColor(bgColorText.value);
    if (!normalized) {
      bgColorText.value = bgColorInput.value.toUpperCase();
      setStatus('Format warna tidak valid. Gunakan format seperti #2D2D2D.');
      return;
    }

    applyBaseBackgroundColor(normalized);
    setStatus(`Warna latar diubah ke ${normalized.toUpperCase()}.`);
  });
  formatSelect.addEventListener('change', () => {
    setFormat(formatSelect.value);
    setStatus(`Ukuran diubah ke ${FORMATS[formatSelect.value].label}.`);
  });

  zoomRange.addEventListener('input', () => {
    setZoom(zoomRange.value);
  });

  zoomInBtn.addEventListener('click', () => {
    setZoom(state.scale + ZOOM_STEP * 8);
  });

  zoomOutBtn.addEventListener('click', () => {
    setZoom(state.scale - ZOOM_STEP * 8);
  });

  resetPositionBtn.addEventListener('click', () => {
    resetPosition();
    setStatus('Posisi dan zoom di-reset.');
  });

  darkModeToggle.addEventListener('click', () => {
    document.documentElement.classList.toggle('dark');
  });

  templateButtons.forEach((button) => {
    button.addEventListener('click', () => {
      const templateName = button.dataset.template || 'minimal';
      setTemplate(templateName);
      setStatus(`Template aktif: ${templateName}.`);
    });
  });

  themeButtons.forEach((button) => {
    button.addEventListener('click', () => {
      const themeName = button.dataset.theme || 'light';
      setTheme(themeName);
      setStatus(themeName === 'moonless' ? 'Versi Moonless Night aktif.' : 'Versi Light aktif.');
    });
  });

  exportBtn.addEventListener('click', async () => {
    setStatus('Memproses export PNG...');
    exportBtn.disabled = true;

    try {
      const dataUrl = await htmlToImage.toPng(postPreview, {
        cacheBust: true,
        pixelRatio: 1,
        width: state.width,
        height: state.height,
      });

      const link = document.createElement('a');
      link.download = 'bpad-post.png';
      link.href = dataUrl;
      link.click();

      setStatus('Export berhasil: bpad-post.png');
    } catch (error) {
      console.error(error);
      setStatus('Export gagal. Coba gunakan gambar dengan ukuran lebih kecil.');
    } finally {
      exportBtn.disabled = false;
    }
  });

  const getDefaultLogoDataUrl = () => {
    const defaultLogoSvg = encodeURIComponent(`
      <svg xmlns='http://www.w3.org/2000/svg' width='240' height='240' viewBox='0 0 240 240'>
        <rect width='240' height='240' rx='30' fill='#ffffff'/>
        <path d='M120 34l56 28v52c0 44-32 79-56 91-24-12-56-47-56-91V62l56-28z' fill='#0f766e'/>
        <path d='M120 62l30 14v35c0 26-18 47-30 55-12-8-30-29-30-55V76l30-14z' fill='#ffffff'/>
      </svg>
    `);
    return `data:image/svg+xml;charset=UTF-8,${defaultLogoSvg}`;
  };

  const setDefaultAssets = () => {
    const defaultBackgroundSvg = encodeURIComponent(`
      <svg xmlns='http://www.w3.org/2000/svg' width='1600' height='1600' viewBox='0 0 1600 1600'>
        <defs>
          <linearGradient id='g1' x1='0' y1='0' x2='1' y2='1'>
            <stop offset='0%' stop-color='#0f766e'/>
            <stop offset='55%' stop-color='#0f172a'/>
            <stop offset='100%' stop-color='#1d4ed8'/>
          </linearGradient>
        </defs>
        <rect width='1600' height='1600' fill='url(#g1)'/>
        <circle cx='1240' cy='340' r='260' fill='rgba(255,255,255,0.14)'/>
        <circle cx='420' cy='1230' r='340' fill='rgba(255,255,255,0.10)'/>
      </svg>
    `);

    bgImage.src = `data:image/svg+xml;charset=UTF-8,${defaultBackgroundSvg}`;
    logoImage.src = DEFAULT_LOGO_DATA_URL;
    logoImage.alt = 'Logo NTT';
    logoImage.onerror = () => {
      logoImage.onerror = null;
      logoImage.src = getDefaultLogoDataUrl();
      setStatus('logo NTT tidak ditemukan, logo default dipakai.');
    };
  };

  const resizeObserver = new ResizeObserver(updatePreviewScale);
  resizeObserver.observe(previewViewport);
  window.addEventListener('resize', updatePreviewScale);

  setDefaultAssets();
  setStatus('Logo NTT aktif otomatis. Siap membuat konten.');
  setFormat('portrait');
  setTemplate('minimal');
  setTheme('light');
  applyBaseBackgroundColor('#0f172a');
  updateTexts();
  resetPosition();
  updatePreviewScale();
})();
